module RefModule(
	input clk,
	input reset,
	input load,
	input [4:0] d,
	output reg [4:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
	if (reset)
		q <= 5'b00000;
	else if (load)
		q <= d;
	else
		q <= q + 1;

endmodule
